def execute_dynamic_script_aggregation(script_code: str, aggregation_name: str = "script_agg_result", params: dict = None):
    """
    Executes an Elasticsearch aggregation using a dynamic Painless script.
    Assumes `script.inline: true` is enabled in Elasticsearch cluster config.

    Args:
        script_code: The Painless script code (e.g., from req.json['script']).
        aggregation_name: The name for the aggregation in the results.
        params: Optional dictionary of parameters to pass to the script.
    
    Returns:
        The value of the script aggregation result, or None if an error occurs.
    """
    script_definition = {
        "source": script_code,
        "lang": "painless"
    }
    if params:
        script_definition["params"] = params

    query_body = {
        "size": 0,  # We only need aggregation results, not hits
        "aggs": {
            aggregation_name: {
                "sum": {  # Using 'sum' as a common aggregation type with scripts
                    "script": script_definition
                }
            }
        }
    }

    try:
        response = es.search(index=INDEX_NAME, body=query_body)
        return response['aggregations'][aggregation_name]['value']
    except Exception as e:
        print(f"Error executing script aggregation '{aggregation_name}': {e}")
        return None

